MOD = 10**9 + 7

def compute_gcd_sum(K, dimensions):
    def lcm(x, y):
        return x * y // gcd(x, y)

    def lcm_multiple(nums):
        return reduce(lcm, nums, 1)

    def count_divisors(n):
        divisors = [0] * (n + 1)
        for i in range(1, n + 1):
            for j in range(i, n + 1, i):
                divisors[j] += 1
        return divisors

    total_sum = 0
    divisors_count = [count_divisors(d) for d in dimensions]

    for comb in product(range(1, min(dimensions) + 1), repeat=K):
        lcm_value = lcm_multiple(comb)
        count = 1
        for d, c in zip(dimensions, comb):
            count *= divisors_count[d][c]

        total_sum += lcm_value * count

    return total_sum % MOD

