MOD = 10**9 + 7

def golomb(n):
    if n == 1:
        return 1
    return 1 + golomb(n - golomb(golomb(n - 1)))

def precompute_golomb(max_val):
    golomb_values = [0] * (max_val + 1)
    for i in range(1, max_val + 1):
        golomb_values[i] = golomb(i)
    return golomb_values

def sum_of_squares(L, R, golomb_values):
    return sum(golomb_values[L-1]**2 for i in range(L-1, R)) % MOD

