import sys
from collections import defaultdict, deque

input = sys.stdin.read
data = input().split()

n = int(data[0])
edges = [tuple(map(int, data[i:i+2])) for i in range(1, 2 * n - 1, 2)]
q = int(data[2 * n])

graph = defaultdict(list)
for u, v in edges:
    graph[u].append(v)
    graph[v].append(u)

def bfs(start, important):
    visited = set()
    queue = deque([start])
    visited.add(start)
    while queue:
        node = queue.popleft()
        for neighbor in graph[node]:
            if neighbor not in visited and neighbor not in important:
                visited.add(neighbor)
                queue.append(neighbor)
    return len(visited) < len(important)

plans = []
index = 2 * n + 1
for _ in range(q):
    k = int(data[index])
    important = set(map(int, data[index+1:index+k+1]))
    index += k + 1
    plans.append((k, important))

results = []
for k, important in plans:
    all_visited = set()
    for i in range(1, n+1):
        if i in important and not bfs(i, important):
            all_visited.update(graph[i])
    if len(all_visited.intersection(important)) == k:
        results.append(-1)
    else:
        results.append(k - len(all_visited.intersection(important)))

print('\n'.join(map(str, results)))

