from collections import defaultdict

input = sys.stdin.read
data = input().split()

n = int(data[0])
edges = []
index = 1
for _ in range(n - 1):
    u = int(data[index]) - 1
    v = int(data[index + 1]) - 1
    edges.append((u, v))
    index += 2

q = int(data[index])
queries = []
index += 1
for _ in range(q):
    k = int(data[index])
    query = list(map(int, data[index + 1:index + 1 + k]))
    queries.append((k, query))
    index += 1 + k

graph = defaultdict(list)
for u, v in edges:
    graph[u].append(v)
    graph[v].append(u)

def dfs(node, parent, visited):
    stack = [node]
    while stack:
        current = stack.pop()
        if current not in visited:
            visited.add(current)
            for neighbor in graph[current]:
                if neighbor != parent:
                    stack.append(neighbor)

def min_capture(cities):
    visited = set()
    components = 0
    for city in cities:
        if city not in visited:
            dfs(city, -1, visited)
            components += 1
    return max(components - 1, 0)

results = []
for k, query in queries:
    if k == len(graph):
        results.append(-1)
    else:
        results.append(min_capture(query))

print('\n'.join(map(str, results)))

