        rootY = find(parent, y)

        if rootX != rootY:
            if rank[rootX] > rank[rootY]:
                parent[rootY] = rootX
            elif rank[rootX] < rank[rootY]:
                parent[rootX] = rootY
            else:
                parent[rootY] = rootX
                rank[rootX] += 1

    def max_depth(city, parent, depth, visited):
        visited[city] = True
        current_max = depth[city]
        for neighbor in graph[city]:
            if not visited[neighbor]:
                current_max = max(current_max, max_depth(neighbor, parent, depth, visited))
        return current_max

