    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def bfs(important_cities):
        visited = [-1] * n
        queue = deque()
        for city in important_cities:
            if visited[city] == -1:
                visited[city] = 0
                queue.append(city)

        while queue:
            current = queue.popleft()
            for neighbor in graph[current]:
                if visited[neighbor] == -1:
                    visited[neighbor] = visited[current] + 1
                    queue.append(neighbor)

