class Solution:
    def construct_string(self, n, m, s, a):
        if m > n or (m == n and '?' not in s):
            return "-1"

        i = 0
        j = 0
        result = list(s)

        while i < n and j < m:
            if s[i] == '?':
                for char in 'abcde':
                    if self.is_valid(result[:i] + [char] + result[i+1:], a):
                        result[i] = char
                        break
                else:
                    return "-1"
            elif s[i] == a[j]:
                j += 1
            i += 1

        return ''.join(result) if j == m else "-1"

    def is_valid(self, s, a):
        i = 0
        j = 0
        while i < len(s) and j < len(a):
            if s[i] == a[j]:
                j += 1
            i += 1
        return j == len(a)

