from collections import defaultdict, deque

def read_input():
    input = sys.stdin.read
    data = input().split()

    index = 0
    def next_int():
        nonlocal index
        result = int(data[index])
        index += 1
        return result

    n = next_int()
    m = next_int()

    adjacency_list = defaultdict(list)
    for _ in range(n):
        si = next_int()
        types = [next_int() for _ in range(si)]
        for i in range(1, len(types)):
            adjacency_list[types[i-1]].append(types[i])
            adjacency_list[types[i]].append(types[i-1])

    edges = []
    for _ in range(n - 1):
        u = next_int()
        v = next_int()
        edges.append((u, v))

    return n, m, adjacency_list, edges

def bfs_coloring(adjacency_list, m):
    colors = [-1] * (m + 1)
    queue = deque()

    # Start BFS from the first node
    for i in range(1, m + 1):
        if colors[i] == -1:
            colors[i] = 1
            queue.append(i)

            while queue:
                current = queue.popleft()
                for neighbor in adjacency_list[current]:
                    if colors[neighbor] == -1:
                        colors[neighbor] = colors[current] ^ 1
                        queue.append(neighbor)
                    elif colors[neighbor] == colors[current]:
                        raise ValueError("Graph is not bipartite")

    return max(colors)

