        count = 0
        for j in range(m):
            if assignment[i*m+j] == 1:
                count += 1
                if count > 1:
                    valid = False
                    break
            else:
                count = 0
        if not valid:
            break
        for j in range(m):
            if assignment[i*m+j] == 1:
                floor[i][j] = 1

    if valid:
        quality = calculate_quality(floor)
        max_quality = max(max_quality, quality)

print(max_quality)

