import sys
from collections import defaultdict

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def read_int():
    return int(sys.stdin.readline())

def read_ints():
    return list(map(int, sys.stdin.readline().split()))

def main():
    t = read_int()
    results = []

    for _ in range(t):
        n, m = read_ints()
        right_values = read_ints()

        # Create adjacency list
        adj_list = defaultdict(list)
        for _ in range(m):
            u, v = read_ints()
            adj_list[u].append(v)

        # Calculate f(S) for all non-empty subsets S
        all_sums = set()
        for mask in range(1, 1 << n):
            current_sum = 0
            for i in range(n):
                if mask & (1 << i):
                    current_sum += sum(right_values[j - 1] for j in adj_list[i + 1])
            all_sums.add(current_sum)

        # Calculate GCD of all sums
        result = all_sums.pop() if all_sums else 0
        for s in all_sums:
            result = gcd(result, s)

        results.append(result)

    for result in results:
        print(result)

if __name__ == "__main__":
    main()
